// And groups predicates with the AND operator between them.
func And(predicates ...predicate.AgentCaseStep) predicate.AgentCaseStep {
	return predicate.AgentCaseStep(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.AgentCaseStep) predicate.AgentCaseStep {
	return predicate.AgentCaseStep(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.AgentCaseStep) predicate.AgentCaseStep {
	return predicate.AgentCaseStep(sql.NotPredicates(p))
}
